namespace sv_23cdee31423d4bc68af42d64702d75b0.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_23cdee31423d4bc68af42d64702d75b0.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="d-flex flex-row gap-4">
    <!-- Left Sidebar -->
    <div class="flex-shrink-0" style="width: 25%;">
        <div class="card">
            <div class="card-header fw-bold">Filters</div>
            <div class="card-body">
                <!-- Category Checkboxes -->
                <h6>Category</h6>
                @if (categories is not null)
                {
                    @foreach (var category in categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                                   checked="@selectedCategories.Contains(category)"
                                   @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                        </div>
                    }
                }
                else
                {
                    <p class="text-muted">Loading categories…</p>
                }

                <hr />

                <!-- Price Range -->
                <h6>Price Range</h6>
                <div class="mb-2">
                    <label class="form-label">Min Price</label>
                    <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                           @bind="minPrice" placeholder="No min" />
                </div>
                <div class="mb-2">
                    <label class="form-label">Max Price</label>
                    <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                           @bind="maxPrice" placeholder="No max" />
                </div>

                <hr />

                <!-- In Stock Only -->
                <div class="form-check mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly"
                           @bind="inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>

                <!-- Buttons -->
                <div class="d-grid gap-2">
                    <button class="btn btn-primary" @onclick="ApplyFilters" disabled="@isLoading">
                        Apply Filters
                    </button>
                    <button class="btn btn-outline-secondary" @onclick="ClearFilters" disabled="@isLoading">
                        Clear Filters
                    </button>
                </div>
            </div>
        </div>
    </div>

    <!-- Main Content -->
    <div class="flex-grow-1" style="min-width: 0;">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
            </div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary me-2" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
                <span>Loading products…</span>
            </div>
        }
        else if (searchResult is null || searchResult.Items.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products found. Try adjusting your filters.
            </div>
        }
        else
        {
            <!-- Toolbar -->
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="me-2 fw-semibold">Sort by:</label>
                    <select class="form-select form-select-sm d-inline-block w-auto"
                            @onchange="OnSortChanged">
                        @foreach (var option in sortOptions)
                        {
                            <option value="@option.Value" selected="@(sortBy == option.Value)">@option.Label</option>
                        }
                    </select>
                </div>
                <span class="text-muted">
                    Showing @ShowingStart–@ShowingEnd of @searchResult.TotalCount products
                </span>
            </div>

            <!-- Product Grid -->
            <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-3">
                @foreach (var product in searchResult.Items)
                {
                    <div class="col">
                        <div class="card h-100 product-card" @onclick="() => OnProductClicked(product)"
                             style="cursor: pointer;">
                            <!-- Placeholder Image -->
                            <div class="card-img-top bg-light d-flex align-items-center justify-content-center"
                                 style="height: 180px;" role="img" aria-label="@product.Name">
                                <span class="text-muted">📷 @product.Name</span>
                            </div>
                            <div class="card-body d-flex flex-column">
                                <h6 class="card-title">@product.Name</h6>
                                <p class="card-text fw-bold text-primary mb-1">@product.Price.ToString("C")</p>
                                <p class="card-text mb-1">@RenderStars(product.Rating)</p>
                                @if (!product.InStock)
                                {
                                    <span class="badge bg-danger mb-2">Out of Stock</span>
                                }
                                <div class="mt-auto">
                                    <button class="btn btn-sm btn-success w-100"
                                            disabled="@(!product.InStock)"
                                            @onclick="() => AddToCart(product)"
                                            @onclick:stopPropagation="true">
                                        Add to Cart
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                }
            </div>

            <!-- Pagination -->
            @if (TotalPages > 1)
            {
                <nav class="mt-4" aria-label="Product pagination">
                    <ul class="pagination justify-content-center">
                        <li class="page-item @(currentPage == 1 ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(currentPage - 1)"
                                    disabled="@(currentPage == 1)">Previous</button>
                        </li>
                        @for (int i = 1; i <= TotalPages; i++)
                        {
                            var pageNum = i;
                            <li class="page-item @(currentPage == pageNum ? "active" : "")">
                                <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
                            </li>
                        }
                        <li class="page-item @(currentPage == TotalPages ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(currentPage + 1)"
                                    disabled="@(currentPage == TotalPages)">Next</button>
                        </li>
                    </ul>
                </nav>
            }
        }
    </div>
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? categories;
    private PagedResult<Product>? searchResult;
    private string? errorMessage;
    private bool isLoading = true;

    // Filter state
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    // Pagination & sorting
    private int currentPage = 1;
    private const int PageSize = 9;
    private string sortBy = "price_asc";

    private static readonly (string Value, string Label)[] sortOptions =
    [
        ("price_asc", "Price: Low to High"),
        ("price_desc", "Price: High to Low"),
        ("name_asc", "Name: A-Z"),
        ("rating_desc", "Rating: Highest"),
    ];

    private int TotalPages => searchResult is null || searchResult.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)searchResult.TotalCount / PageSize);

    private int ShowingStart => (searchResult!.Page - 1) * searchResult.PageSize + 1;

    private int ShowingEnd => Math.Min(searchResult!.Page * searchResult.PageSize, searchResult.TotalCount);

    protected override async Task OnInitializedAsync()
    {
        await LoadCategoriesAndProducts();
    }

    private async Task LoadCategoriesAndProducts()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = PerformSearch();

            categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task PerformSearch()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            searchResult = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await PerformSearch();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        sortBy = "price_asc";
        await PerformSearch();
    }

    private async Task OnSortChanged(ChangeEventArgs e)
    {
        sortBy = e.Value?.ToString() ?? "price_asc";
        currentPage = 1;
        await PerformSearch();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > TotalPages)
            return;

        currentPage = page;
        await PerformSearch();
    }

    private async Task OnProductClicked(Product product)
    {
        if (OnProductSelected.HasDelegate)
        {
            await OnProductSelected.InvokeAsync(product);
        }
    }

    private void AddToCart(Product product)
    {
        // Placeholder for cart functionality
    }

    private static string RenderStars(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}

